('cp05a2fe7244f34ebb87555f951abb4f82', NULL, 'Get the birds out to kla ugad', 'Looking for fashion influencers to promote our summer collection. Must have at least 10K followers on Instagram and demonstrate engagement with fashion content. Campaign will run for 2 weeks with multiple deliverables including posts, stories, and reels.', 'brand_awareness', '2027-02-15', 0.00, 'b82aa423d2eef4fceb6aac311d153b277', 'deleted', '2027-02-01', 10000.00, 0.00, 'https://social-gems.s3.amazonaws.com/gems/1752477992399-yn6u0dayl.png', NULL, 'na', '89899898998', '2025-10-12 13:32:31', NULL, NULL, 5, NULL, NULL, 'b82aa423d2eef4fceb6aac311d153b277', '89899898998', 'agent'),
('cp0f9c9f23f0464af39395c1e7e7b5e2ee', NULL, 'GlowUp Challenge', 'It’s time to celebrate your confidence and natural glow! ✨\nThe GlowUp Challenge invites influencers and everyday creators to show how they shine — inside and out. Whether it’s your skincare routine, your favorite outfit, or a simple smile, we want to see your authentic glow moments.\n\nThis campaign aims to inspire self-confidence and promote positive self-image through real stories and visuals. Participants will engage with the brand, share personal confidence tips, and encourage others to embrace their own journey to self-love.\n\nObjective:\n\nDrive engagement through authentic, feel-good content.\n\nPromote the brand as a symbol of confidence and positivity.\n\nIncrease awareness across social media platforms.\n\nTone & Style:\nFriendly, inspiring, and confident — visuals should feel warm, natural, and empowering.', 'Boost Sales Conversion', '2025-10-26', 0.00, 'bfc40f8f0f16146cbb965bbec69df434a', 'draft', '2025-10-24', 200.00, 0.00, 'https://sg-cdn.tekjuice.xyz/gems/1760948061734-ef0ozz7u1.png', NULL, 'na', NULL, '2025-10-20 08:14:22', NULL, NULL, 5, NULL, NULL, 'bfc40f8f0f16146cbb965bbec69df434a', '89899898998', 'agent'),
