('cp3890699d87cc43289ec41dabfb28176b', NULL, 'Bright Mornings with Bar Air', 'Start your day with a touch of inspiration! ✈️\nOur Bright Mornings with Bar Air broadcast campaign shares uplifting stories, travel tips, and exclusive flight offers every morning to keep our audience excited about their next adventure. The campaign runs daily at 9 AM, reaching frequent travelers and adventure lovers across the country through SMS, email, and social media broadcasts.\n\nBy combining motivation, deals, and engaging visuals, this campaign aims to increase morning engagement by 40% and boost seat bookings by 25% within the first month. It’s not just about flying — it’s about starting every day with purpose, excitement, and the promise of discovery.', 'Drive Website Traffic', '2025-10-22', 0.00, 'b82aa423d2eef4fceb6aac311d153b277', 'draft', '2025-10-18', 100.00, 0.00, 'https://sg-cdn.tekjuice.xyz/gems/1760417372478-1ut8o0h88.jpg', NULL, 'na', NULL, '2025-10-14 04:49:33', NULL, NULL, 2, NULL, NULL, 'b82aa423d2eef4fceb6aac311d153b277', '89899898998', 'agent'),
('cp3b1dab5c37b34972871a04dc13b8aaf0', NULL, 'Brush and Beats', 'A Campaign to tell people about the importance of Thick thighs in Global warming. This campaign will run on all social media platforms and create the sort of buzz we are looking for as Team Thick Thighs.', 'Expand Market Reach', '2025-11-03', 0.00, 'br977bc0a373ad4d47a835affd54fe7d37', 'completed', '2025-10-22', 85.00, 85.00, 'https://sg-cdn.tekjuice.xyz/gems/1761137165044-zn03vlop6.jpg', NULL, 'grp_ce1d56b1e9b64e6aad768e873552c1dd', NULL, '2025-10-22 12:46:06', '2025-10-22', '2025-10-22 13:16:01', 3, '2025-10-22 12:53:38', '2025-10-22 12:51:57', 'br977bc0a373ad4d47a835affd54fe7d37', 'agf949ddac33b244228c8940ca3c2b2d4b', 'agent'),
