('cpdc89e86322fa4c19a74bd1b7bae009cc', NULL, 'The Gems Kala', '<p style=\"max-width: 900px; margin-top: 8px; margin-bottom: 8px; color: rgb(15, 23, 42); font-family: Arial, Helvetica, sans-serif; font-size: medium;\"><b style=\"display: block; font-size: 18px; margin-bottom: 6px;\"><b style=\"margin-bottom: 6px; display: inline !important;\">Campaign Mission</b></b></p><p style=\"max-width: 900px; margin-top: 8px; margin-bottom: 8px; color: rgb(15, 23, 42); font-family: Arial, Helvetica, sans-serif; font-size: medium;\">Predict. Win. Earn. We’re bringing the excitement of sports and blockchain together through SiaBet — the next generation of social prediction markets. Our mission is to create authentic, engaging content that inspires users to join siabet.online, download the app, and become part of a thriving community of smart predictors.</p><p style=\"max-width: 900px; margin-top: 8px; margin-bottom: 8px; color: rgb(15, 23, 42); font-family: Arial, Helvetica, sans-serif; font-size: medium;\"><b style=\"display: block; font-size: 18px; margin-bottom: 6px;\">What We\'re Looking For</b></p><p style=\"max-width: 900px; margin-top: 8px; margin-bottom: 8px; color: rgb(15, 23, 42); font-family: Arial, Helvetica, sans-serif; font-size: medium;\">Genuine, authentic content showcasing the SiaBet experience naturally. High-quality visuals (screenshots, reels, stories) featuring the SiaBet app, games, or community. Compelling captions that spark excitement around predicting and winning. Strategic hashtag usage to maximize reach and discoverability.</p><p style=\"max-width: 900px; margin-top: 8px; margin-bottom: 8px; color: rgb(15, 23, 42); font-family: Arial, Helvetica, sans-serif; font-size: medium;\"><b style=\"display: block; font-size: 18px; margin-bottom: 6px;\">Content Requirements</b></p><p style=\"max-width: 900px; margin-top: 8px; margin-bottom: 8px; color: rgb(15, 23, 42); font-family: Arial, Helvetica, sans-serif; font-size: medium;\">Include brand mentions: @SiaBetOfficial and hashtags: #SiaBet #PredictWinEarn #SBXToken. Feature clear call-to-actions such as \"Download the SiaBet app today\" and \"Play now at siabet.online\". Highlight key features: instant rewards, multi-chain support, social predictions, leaderboard system. Showcase popular games like Football, Cricket, or Tennis. Post during your audience’s peak engagement hours.</p><p style=\"max-width: 900px; margin-top: 8px; margin-bottom: 8px; color: rgb(15, 23, 42); font-family: Arial, Helvetica, sans-serif; font-size: medium;\"><b style=\"display: block; font-size: 18px; margin-bottom: 6px;\">Creative Freedom</b></p><p style=\"max-width: 900px; margin-top: 8px; margin-bottom: 8px; color: rgb(15, 23, 42); font-family: Arial, Helvetica, sans-serif; font-size: medium;\">Bring your unique style — whether through sports commentary, tutorials, lifestyle content, or gamified storytelling. Keep the SiaBet brand voice: transparent, secure, innovative, and community-driven.</p><p style=\"max-width: 900px; margin-top: 8px; margin-bottom: 8px; color: rgb(15, 23, 42); font-family: Arial, Helvetica, sans-serif; font-size: medium;\"><b style=\"display: block; font-size: 18px; margin-bottom: 6px;\">Collaboration Benefits</b></p><p style=\"max-width: 900px; margin-top: 8px; margin-bottom: 8px; color: rgb(15, 23, 42); font-family: Arial, Helvetica, sans-serif; font-size: medium;\">Exclusive access to SBX token rewards. Early access to upcoming platform features. Referral bonuses for driving engagement. Competitive compensation and brand partnerships.</p><p style=\"max-width: 900px; margin-top: 8px; margin-bottom: 8px; color: rgb(15, 23, 42); font-family: Arial, Helvetica, sans-serif; font-size: medium;\"><b style=\"display: block; font-size: 18px; margin-bottom: 6px;\">Campaign Timeline</b></p><p style=\"max-width: 900px; margin-top: 8px; margin-bottom: 8px; color: rgb(15, 23, 42); font-family: Arial, Helvetica, sans-serif; font-size: medium;\">Content creation deadline: [Insert Date]. Publishing schedule: [Insert Date Range]. Campaign duration: [Insert Start Date] → [Insert End Date].</p><p style=\"max-width: 900px; margin-top: 8px; margin-bottom: 8px; color: rgb(15, 23, 42); font-family: Arial, Helvetica, sans-serif; font-size: medium;\"><b style=\"display: block; font-size: 18px; margin-bottom: 6px;\">Platform Highlights</b></p><p style=\"max-width: 900px; margin-top: 8px; margin-bottom: 8px; color: rgb(15, 23, 42); font-family: Arial, Helvetica, sans-serif; font-size: medium;\">Popular Games: Football, Cricket, Tennis. Active Players: 2.5K per game (example). Prize Pools: $5000 (example). SBX Token Utility: reduced fees, access to exclusive predictions, governance participation, staking for passive rewards.</p><p style=\"max-width: 900px; margin-top: 8px; margin-bottom: 8px; color: rgb(15, 23, 42); font-family: Arial, Helvetica, sans-serif; font-size: medium;\"><b style=\"display: block; font-size: 18px; margin-bottom: 6px;\">How to Play (Short)</b></p><p style=\"max-width: 900px; margin-top: 8px; margin-bottom: 8px; color: rgb(15, 23, 42); font-family: Arial, Helvetica, sans-serif; font-size: medium;\">Choose your sport, make your prediction using cryptocurrency, and earn rewards when your predictions are correct. Climb the leaderboard for bonus rewards.<br></p>', 'SEO & Organic Visibility', '2025-10-31', 0.00, 'u2daf21c9343942839005bbb0091b232f', 'open_to_applications', '2025-09-29', 895.00, 0.00, 'https://sg-cdn.tekjuice.xyz/gems/1758617034976-a500tgp2v.jpg', NULL, 'na', NULL, '2025-09-23 08:43:56', NULL, NULL, 10, NULL, '2025-09-23 09:05:03', 'u2daf21c9343942839005bbb0091b232f', 'u2daf21c9343942839005bbb0091b232f', 'brand'),
('cpe36c724392e54ca49c577c3a8c8b8025', NULL, 'Get the birds out to kla ugad', 'Looking for fashion influencers to promote our summer collection. Must have at least 10K followers on Instagram and demonstrate engagement with fashion content. Campaign will run for 2 weeks with multiple deliverables including posts, stories, and reels.', 'brand_awareness', '2027-02-15', 0.00, 'b82aa423d2eef4fceb6aac311d153b277', 'deleted', '2027-02-01', 10000.00, 0.00, 'https://social-gems.s3.amazonaws.com/gems/1752477992399-yn6u0dayl.png', NULL, 'na', '89899898998', '2025-10-12 14:23:56', NULL, NULL, 5, NULL, NULL, 'b82aa423d2eef4fceb6aac311d153b277', '89899898998', 'agent'),
('cpe42c7c085e7d40e4832e4fb263308b84', NULL, 'Church Building Fundraiser', '<p data-start=\"230\" data-end=\"292\"><strong data-start=\"230\" data-end=\"292\">🏗️ Building for the Future – A Campaign of Faith &amp; Vision</strong></p><br>\n<p data-start=\"294\" data-end=\"317\"><strong data-start=\"294\" data-end=\"317\">Dear Church Family,</strong></p><br>\n<p data-start=\"319\" data-end=\"573\">We are standing at a pivotal moment in the life of our church—a moment filled with promise, purpose, and possibility. With grateful hearts for all that God has done in and through our ministry, we now look forward to the future He is calling us to build.</p><br>\n<p data-start=\"575\" data-end=\"589\"><strong data-start=\"575\" data-end=\"589\">The Vision</strong></p><br><p data-start=\"591\" data-end=\"885\">Our mission has always been to glorify God by reaching the lost, nurturing believers, and serving our community. As we continue to grow, both spiritually and numerically, we are stepping out in faith to expand our physical space so that we can continue to fulfill this mission more effectively.</p>\n<p data-start=\"887\" data-end=\"1179\">Our new building will serve as a <strong data-start=\"920\" data-end=\"938\">beacon of hope</strong>, a <strong data-start=\"942\" data-end=\"962\">house of worship</strong>, and a <strong data-start=\"970\" data-end=\"990\">center of impact</strong> for generations to come. It will provide expanded worship space, classrooms for discipleship and youth ministry, facilities for outreach, and areas for fellowship and ministry development.</p><br>\n<p data-start=\"1181\" data-end=\"1193\"><strong data-start=\"1181\" data-end=\"1193\">Why Now?</strong></p>\n<ul data-start=\"1195\" data-end=\"1499\">\n<li data-start=\"1195\" data-end=\"1263\">\n<p data-start=\"1197\" data-end=\"1263\">Our current facility is limiting our growth and outreach capacity.</p>\n</li>\n<li data-start=\"1264\" data-end=\"1330\">\n<p data-start=\"1266\" data-end=\"1330\">Our children\'s and youth ministries are outgrowing their spaces.</p>\n</li>\n<li data-start=\"1331\" data-end=\"1413\">\n<p data-start=\"1333\" data-end=\"1413\">We need a space that reflects the heart and vision of our church for the future.</p>\n</li>\n<li data-start=\"1414\" data-end=\"1499\">\n<p data-start=\"1416\" data-end=\"1499\">God has opened a door for us to step into this opportunity with boldness and faith.</p><br>\n</li>\n</ul>\n<p data-start=\"1501\" data-end=\"1535\"><strong data-start=\"1501\" data-end=\"1535\">The Campaign: \"Built on Faith\"</strong></p>\n<p data-start=\"1537\" data-end=\"1815\">We are launching our <strong data-start=\"1558\" data-end=\"1597\">Building Campaign: “Built on Faith”</strong>—a journey to raise the resources needed to construct our new facility. This is more than a fundraiser; it\'s a spiritual journey where each of us can prayerfully consider how God is calling us to invest in His Kingdom.</p><br><p data-start=\"1817\" data-end=\"1844\"><strong data-start=\"1817\" data-end=\"1844\">How You Can Be Involved</strong></p>\n<ol data-start=\"1846\" data-end=\"2314\">\n<li data-start=\"1846\" data-end=\"1949\">\n<p data-start=\"1849\" data-end=\"1949\"><strong data-start=\"1849\" data-end=\"1857\">Pray</strong> – Ask God to guide our church through this process and to move in the hearts of His people.</p>\n</li>\n<li data-start=\"1950\" data-end=\"2107\">\n<p data-start=\"1953\" data-end=\"2107\"><strong data-start=\"1953\" data-end=\"1961\">Give</strong> – We’re asking each member to make a sacrificial financial commitment—above and beyond regular giving—over the next [3 years or campaign period].</p>\n</li>\n<li data-start=\"2108\" data-end=\"2217\">\n<p data-start=\"2111\" data-end=\"2217\"><strong data-start=\"2111\" data-end=\"2120\">Serve</strong> – Join the building committee, volunteer teams, or campaign efforts as we move forward together.</p>\n</li>\n<li data-start=\"2218\" data-end=\"2314\">\n<p data-start=\"2221\" data-end=\"2314\"><strong data-start=\"2221\" data-end=\"2230\">Share</strong> – Spread the vision and invite others to be part of what God is doing in our midst.</p><br>\n</li>\n</ol>\n<p data-start=\"2316\" data-end=\"2338\"><strong data-start=\"2316\" data-end=\"2338\">Together, We Build</strong></p>\n<p data-start=\"2340\" data-end=\"2593\">This is more than bricks and mortar—it\'s about building lives, building legacy, and building for the Kingdom. Let us rise together in unity and purpose, just as Nehemiah and the people of Jerusalem did, to rebuild and renew what God has called us to do.</p>\n<p data-start=\"2595\" data-end=\"2769\">We invite you to prayerfully join us in this exciting season. May we build—not just for today—but for the generations who will come to know Christ through the work we do now.</p>\n<p data-start=\"2771\" data-end=\"2852\"><strong data-start=\"2771\" data-end=\"2852\">“Unless the Lord builds the house, the builders labor in vain…” – Psalm 127:1</strong></p><br><br>\n<p data-start=\"2854\" data-end=\"2864\">In Christ,</p>\n<p data-start=\"2866\" data-end=\"2948\"><em data-start=\"2866\" data-end=\"2895\">Your Church Leadership Team</em><br data-start=\"2895\" data-end=\"2898\">Christ Life Church<br data-start=\"2911\" data-end=\"2914\">Kampala Uganda</p>', 'Engagement & Community Building', '2025-09-30', 0.00, 'b828693e097414e73a45964f1cd981937', 'open_to_applications', '2025-08-29', 700.00, 0.00, 'https://social-gems.s3.amazonaws.com/gems/1755870103648-29plminay.jpg', NULL, 'na', NULL, '2025-08-22 13:41:44', NULL, NULL, 10, NULL, '2025-08-22 13:59:35', 'b828693e097414e73a45964f1cd981937', 'b828693e097414e73a45964f1cd981937', 'brand'),
('cpe9b30b7c294c4fbb8fd5850cd443b76f', '03603410-8a0c-49b6-bbfd-3fd3b803373c', 'test 7', '<p>Msflutter: ║            },<br/>flutter: ║          {id: 19, objective: Lead Generation &amp; List Growth, created_at: 2025-04-30T07:53:33.000Z},<br/>flutter: ║          {id: 6, objective: SEO &amp; Organic Visibility, created_at: 2025-04-29T19:34:56.000Z},<br/>flutter: ║          {id: 5, objective: Engagement &amp; Community Building, created_at: 2025-04-29T15:22:30.000Z},<br/>flutter: ║            {<br/>flutter: ║                 &quot;id&quot;: 4,<br/>flutter: ║                 &quot;objective&quot;: &quot;Content Creation &amp; Asset Library&quot;,<br/>flutter: ║                 &quot;created_at&quot;: &quot;2025-04-29T15:09:53.000Z&quot;<br/>flutter: ║            },<br/>flutter: ║          {id: 3, objective: Brand Awareness &amp; Reach, created_at: 2025-04-29T14:51:09.000Z},<br/>flutter: ║          {id: 2, objective: Sales &amp; Revenue Conversion, created_at: 2025-04-29T14:35:04.000Z}<br/></p>', 'Market Insights & Product Testing', '2025-10-14', 0.00, 'bef55976ef0454c51a741fa98356271e4', 'deleted', '2025-10-12', 24.00, 0.00, 'https://sg-cdn.tekjuice.xyz/gems/1759992716352-kl86xa1hg.tmp-1-1759992571664', NULL, 'na', 'bef55976ef0454c51a741fa98356271e4', '2025-10-09 06:51:56', NULL, NULL, 1, NULL, NULL, 'bef55976ef0454c51a741fa98356271e4', 'bef55976ef0454c51a741fa98356271e4', 'brand'),
