INSERT INTO `act_campaigns` (`campaign_id`, `request_id`, `title`, `description`, `objective`, `end_date`, `reward`, `created_by`, `status`, `start_date`, `budget`, `amount_spent`, `image_urls`, `tasks`, `group_id`, `closed_by`, `created_on`, `closed_date`, `completed_on`, `number_of_influencers`, `activated_on`, `published_date`, `business_id`, `created_by_user_id`, `creator_type`) VALUES
('cpf8d246d695954f3382291b4d9b5c7470', NULL, '“Clean Beyond the Surface” – The Everyday Freshness Campaign', 'The “Clean Beyond the Surface” campaign celebrates the power of a detergent that does more than just wash clothes — it restores freshness, comfort, and confidence to every moment of your day. Designed for today’s busy lifestyles, this campaign showcases how our detergent goes deep into fabric fibers to remove dirt, sweat, and stubborn stains while leaving a long-lasting fresh scent that keeps you feeling clean all day.\n\nThrough vibrant storytelling and relatable visuals, the campaign captures families, professionals, and everyday heroes who trust our detergent to keep their clothes spotless and soft. It emphasizes that cleanliness isn’t just about appearance — it’s about feeling good, confident, and ready to take on the world.\n\nWith a focus on deep cleaning technology, freshness, and care, the campaign reinforces our promise: every wash brings not just clean clothes, but a clean start.', 'Generate Leads', '2025-10-23', 0.00, 'b1cc8b76ecd564cae93266ffd3e6d3745', 'draft', '2025-10-18', 22.00, 0.00, 'https://sg-cdn.tekjuice.xyz/gems/1760429690645-dy402i2t7.webp', NULL, 'na', NULL, '2025-10-14 08:14:51', NULL, NULL, 1, NULL, NULL, 'b1cc8b76ecd564cae93266ffd3e6d3745', '89899898998', 'agent');
