('s0cf48039ea574604b7d5158c8803fb18', 'Sample Activity', 'activity', NULL, NULL, 'Lorem ipsum dora,  Lorem ipsum dora,  Lorem ipsum dora,  Lorem ipsum dora,  Lorem ipsum dora,  Lorem ipsum dora,  Lorem ipsum dora,  Lorem ipsum dora,  Lorem ipsum dora,  Lorem ipsum dora,  Lorem ipsum dora<br>Lorem ipsum dora,  Lorem ipsum dora,  Lorem ipsum dora,  Lorem ipsum dora,  Lorem ipsum dora,  Lorem ipsum dora,  Lorem ipsum dora,  Lorem ipsum dora,  Lorem ipsum dora,  Lorem ipsum dora,  Lorem ipsum dora<br> ', '2026-01-20', 'https://social-gems.s3.amazonaws.com/1731915223896-f3btbep4k.png', 200.00, 'yes', 'yes', NULL, 'daily', '1a6496f7b289450896c0d164c97237e9', 'TS00001', NULL, 'active', '2025-09-10 14:20:19'),
('s1ebc13d425854643ba9671b6416a1884', 'Test: Explore & Discover', 'activity', NULL, NULL, '<p><br></p><ul><li>Open the app and navigate through the main features (feed, profile, notifications, etc.).</li><li>Try uploading a photo or video, liking, and commenting to see how smooth it feels.</li><li>Share your thoughts: Was it easy to use? Did anything feel confusing?</li></ul><p><br></p><p>💎 <strong>Reward:</strong> Earn gems for completing your first exploration and giving feedback.</p>', '2025-09-09', 'https://social-gems.s3.amazonaws.com/gems/1757337818442-g44iw193o.jpg', 0.05, 'yes', 'yes', NULL, NULL, '1a6496f7b289450896c0d164c97237e9', 'TS00001', NULL, 'active', '2025-09-08 13:23:39'),
('s1ee1e2daf2484c8ca9a9b7e08279b825', 'Sample Activity', 'activity', NULL, NULL, '<p>We’re inviting you to be one of the first to try out our new app! 🚀</p><p>Your feedback is super important—it helps us improve and make the app even better for everyone.</p><p><br></p><p>Here’s how it works:</p><p>1️⃣ Download and explore the app.</p><p>2️⃣ Try out different features and share your experience.</p><p>3️⃣ As a thank you, you’ll receive <strong>free gems</strong> that you can use inside the app! 💎</p><p><br></p><p>Not only do you get rewarded, but you’ll also be part of shaping the future of the app. The more you test and share, the more gems you can earn.</p><p><br></p><p>Join us today and start collecting gems while helping us build something amazing! 🙌</p>', '2025-09-09', '', 0.01, 'yes', 'yes', NULL, NULL, '1a6496f7b289450896c0d164c97237e9', 'TS00001', NULL, 'active', '2025-09-08 13:00:37'),
('s677dbd0b1a8744b89d3938f968ce7c67', 'MTN Marathon', 'activity', NULL, NULL, 'Lorem ipsum dora,  Lorem ipsum dora,  Lorem ipsum dora,  Lorem ipsum dora,  Lorem ipsum dora,  Lorem ipsum dora,  Lorem ipsum dora,  Lorem ipsum dora,  Lorem ipsum dora,  Lorem ipsum dora,  Lorem ipsum dora<br>Lorem ipsum dora,  Lorem ipsum dora,  Lorem ipsum dora,  Lorem ipsum dora,  Lorem ipsum dora,  Lorem ipsum dora,  Lorem ipsum dora,  Lorem ipsum dora,  Lorem ipsum dora,  Lorem ipsum dora,  Lorem ipsum dora<br> ', '2026-01-20', 'https://social-gems.s3.amazonaws.com/1731915223896-f3btbep4k.png', 200.00, 'yes', 'yes', NULL, 'daily', '1a6496f7b289450896c0d164c97237e9', 'TS00001', NULL, 'active', '2025-09-10 12:27:14'),
('s9613fd7f6a284eab9ec91be545356414', 'Test: Engage with the Community', 'activity', NULL, NULL, '<p><br></p><ul><li>Follow other users, react to their posts, and send a message.</li><li>Join trending challenges or discover recommended content.</li><li>Let us know if everything loads smoothly and if notifications are working.</li></ul><p><br></p><p>💎 <strong>Reward:</strong> Earn gems for meaningful interactions and feedback on the experience.</p>', '2025-09-09', 'https://social-gems.s3.amazonaws.com/gems/1757337950768-gv1qxcmcr.jpg', 0.05, 'yes', 'yes', NULL, NULL, '1a6496f7b289450896c0d164c97237e9', 'TS00001', NULL, 'active', '2025-09-08 13:25:51'),
('sa0240bc28f084015957d38afadd26c5f', 'Airtel Marathon', 'activity', NULL, NULL, 'Lorem ipsum dora,  Lorem ipsum dora,  Lorem ipsum dora,  Lorem ipsum dora,  Lorem ipsum dora,  Lorem ipsum dora,  Lorem ipsum dora,  Lorem ipsum dora,  Lorem ipsum dora,  Lorem ipsum dora,  Lorem ipsum dora<br>Lorem ipsum dora,  Lorem ipsum dora,  Lorem ipsum dora,  Lorem ipsum dora,  Lorem ipsum dora,  Lorem ipsum dora,  Lorem ipsum dora,  Lorem ipsum dora,  Lorem ipsum dora,  Lorem ipsum dora,  Lorem ipsum dora<br> ', '2026-01-20', 'https://social-gems.s3.amazonaws.com/1731915223896-f3btbep4k.png', 200.00, 'yes', 'yes', NULL, 'daily', '1a6496f7b289450896c0d164c97237e9', 'TS00001', NULL, 'active', '2025-09-10 13:13:31'),
('sfa6285b220184856ab8a46aa539208be', 'Test: Create & Share Content', 'activity', NULL, NULL, '<p><br></p><ul><li>Post your own content (photo, video, or text).</li><li>Test editing tools, captions, and hashtags.</li><li>Share your post with a friend or on another platform to check if sharing works well.</li></ul><p><br></p><p>💎 <strong>Reward:</strong> Collect gems for every piece of content you create and share.</p>', '2025-09-09', 'https://social-gems.s3.amazonaws.com/gems/1757337874240-omdh1bhi6.jpg', 0.05, 'yes', 'yes', NULL, NULL, '1a6496f7b289450896c0d164c97237e9', 'TS00001', NULL, 'active', '2025-09-08 13:24:34'),
