(456, 'u3d5a09adf1af42cdab507390afc4fb2d', 'GENERAL', 'irqb3wgji3@daouse.com', 'Campaign Task Submission Rejected', 'Dear ,\n\n\r\n   Unfortunately, your task submission for a campaign has been rejected by the brand.\n\n\r\n   Rejection Details:\n\r\n   Reason: \n\n\r\n   Please review the campaign requirements and resubmit your work if applicable. If you have any questions about the rejection, please contact the campaign creator or our support team.\n\n\r\n   View My Campaigns\n\n\r\n   Best regards,\n\r\n   The Social Gems Team', '{\"title\":\"Campaign Task Submission Rejected\",\"body\":\"Dear ,\\n\\n\\r\\n   Unfortunately, your task submission for a campaign has been rejected by the brand.\\n\\n\\r\\n   Rejection Details:\\n\\r\\n   Reason: \\n\\n\\r\\n   Please review the campaign requirements and resubmit your work if applicable. If you have any questions about the rejection, please contact the campaign creator or our support team.\\n\\n\\r\\n   View My Campaigns\\n\\n\\r\\n   Best regards,\\n\\r\\n   The Social Gems Team\",\"messageType\":\"SUBMISSION_REJECTED\"}', 'unread', 'ALL', '2025-10-21 15:21:28'),
