INSERT INTO `notification_templates` (`id`, `operation`, `title`, `body`, `channel`, `category`, `status`) VALUES
(4, 'SIGNUP', 'Welcome', '<p>Welcome to Social Gems, use this OTP to activate your account. <strong>{otp}</strong>.</p>', 'ALL', 'GENERAL', 'active'),
(5, 'CHANGE_PASSWORD', 'Password changed', '<p>Hello {name},</p><p>Your password has been reset successfully. You can now log in with your new password, thanks</p>', 'ALL', 'GENERAL', 'active'),
(6, 'RESET_PASSWORD_REQUEST', 'Verification Code', '<p>Hello {name} use <strong>{otp}</strong> as your OTP</p><p><br></p>', 'ALL', 'GENERAL', 'active'),
(7, 'RESET_PASSWORD_COMPLETE', 'Password Reset', '<p>Hello {name},</p><p>Your password has been reset successfully. You can now log in with your new password.</p>', 'ALL', 'GENERAL', 'active'),
(8, 'PAYMENT_RECEIVED', 'GEMS Received', '<p>Hello {name},</p><p> You have received GEM points for completing a task, please check your social Gems app for details.</p>', 'ALL', 'WALLET', 'active'),
(9, 'ACTIVITY_STARTED', 'Activity Started', 'Hello a new activity has started', 'ALL', 'ACTIVITY', 'active'),
(10, 'ACCEPT_INVITE', 'Social Gems', '<p>Hello {name}, You\'ve successfully joined the campaign. Enjoy the experience!</p>', 'ALL', 'CAMPAIGN', 'active'),
(11, 'INVITE_TO_CAMPAIGN', 'Campaign Invitation', 'Hello, you have been invited to join a campaign, please login into your app to view details.', 'ALL', 'CAMPAIGN', 'active'),
(12, 'LEVEL_INCREASE', 'Level Upgraded', 'Congratulations!, you have achieved a new level on social Gems. Please open your app to see your new level.', 'ALL', 'ACTIVITY', 'active'),
(13, 'CAMPAIGN_ADMIN_COMPLETED', 'User completed campaign', 'Hello, a new user has completed one of your campaigns on social gems, open the app to see more', 'ALL', 'CAMPAIGN', 'active'),
(14, 'CAMPAIGN_USER_COMPLETED', 'Campaign Completed', 'Congratulations!, You have submitted your campaign, the brand will check it out and get back to you, thank you for using social Gems.', 'ALL', 'CAMPAIGN', 'active'),
(15, 'DEPOSIT', 'Deposit Received', '<p>Hi {name},</p><p>You\'ve received a deposit of <strong>{otp} USD</strong> in your Social Gems wallet. Check the app for details.</p>', 'ALL', 'WALLET', 'active'),
(16, 'TRANSFER_OUT', 'Transfer Sent', 'Hi {name},\r\n\r\nYour wallet has been debited with {otp} USD as a transfer out.\r\nCheck the app for details.', 'ALL', 'WALLET', 'active'),
(17, 'TRANSFER_IN', 'Transfer received', 'Hi {name},\r\n\r\nYour have received {otp} USD as a transfer in {reason}\r\nCheck the app for details.', 'ALL', 'WALLET', 'active'),
(18, 'ADDED_COMMENT', 'new comment', 'Hi {name} just comment on your post', 'APP', 'POST', 'active'),
(19, 'ADMIN_OTP', 'Social Gems Admin', '<p>Hello {name},</p>\n<p>You have been added to the Social Gems admin panel.</p>\n<p>Please use the following password to log in: <strong>{otp}</strong></p>\n<p>Visit the admin panel here: <a href=\"{SITE_URL}\">{SITE_URL}</a></p>\n', 'ALL', 'GENERAL', 'active'),
(20, 'ADMIN_REACTIVATION', 'Social Gems Admin', '<p>Hello {name},</p>\n<p>Your Social Gems access has been activated.</p>\n<p>Visit the admin panel here: <a href=\"{SITE_URL}\">{SITE_URL}</a></p>\n', 'ALL', 'GENERAL', 'active'),
(21, 'ADMIN_PASSWORD_RESET', 'Social Gems Admin', '<p>Hello {name},</p>\n<p>We received a request to reset your password for the Social Gems admin panel.</p>\n<p>Your temporary password is: <strong>{otp}</strong></p>\n<p>Please log in using this password and update it immediately.</p>\n<p>Access the admin panel here: <a href=\"{SITE_URL}\">{SITE_URL}</a></p>\n<p>If you did not request this reset, please ignore this message.</p>\n', 'ALL', 'GENERAL', 'active'),
(22, 'VERIFY_EMAIL', 'Account verification', '<p>Hello {name} use <strong>{otp}</strong> as your OTP</p><p><br></p>', 'ALL', 'GENERAL', 'active'),
(23, 'UPDATE_PROFILE', 'Profile Update Reward', 'Hello! You\'ve been awarded {amount} GEMs for successfully updating your profile', 'APP', 'GENERAL', 'active'),
(24, 'SIGN_UP_POINTS', 'Signup Reward', 'Hi there! Welcome to Social Gems. ?\r\nAs a welcome gift, you\'ve been awarded {amount} GEM points. We\'re excited to have you on board!', 'APP', 'MARKETING', 'active'),
(25, 'Activity Reward', 'Activity Reward', 'Hello! You\'ve received {amount} GEMS for completing an activity. Keep going—more rewards await!\r\n\r\n', 'APP', 'ACTIVITY', 'active'),
(26, 'UPDATE_PROFILE', 'Profile Update Reward', 'Hello! You\'ve been awarded {amount} GEMs for successfully updating your profile', 'APP', 'GENERAL', 'active'),
(27, 'BLOCKED_POST', 'Blocked Post', 'Your last post was blocked due to inappropriate content, and you have been striked, more strikes will lead to a ban', 'APP', 'POST', 'active'),
(28, 'SOCIAL_VERIFICATION', 'SocialGems Account Verification', '<p>Hello <b>{name}</b>,</p>\n<p>Exciting news! {reason}</p>\n<p>As a token of appreciation, you\'ve earned <b>{amount} Gem points</b>. Keep shining!</p>', 'ALL', 'ANNOUNCEMENT', 'active'),
(29, 'BUSINESS_REJECTED', 'Business Verification Rejected', '<p>Hello <b>{name}</b>,</p>\r\n<p>We regret to inform you that your business verification could not be approved at this time due to <b>{reason}</b>.</p>\r\n<p>Please review the reason above carefully, make the necessary corrections, and submit your application again. Our support team is available if you need any guidance.</p>\r\n', 'ALL', 'GENERAL', 'active'),
(30, 'BUSINESS_APPROVED', 'Business Verification Successful', '<p>Hello <b>{name}</b>,</p>\r\n<p>Good news! Your business verification has been <b>approved</b>.</p>\r\n<p>You can now enjoy full access to our services — load money into your account and start a campaign, or create a free draft campaign today.</p>\r\n', 'ALL', 'ANNOUNCEMENT', 'active'),
(31, 'CAMPAIGN_ACTIVATED', 'CAMPAIGN ACTIVATED', '<p>Hello,</p>\r\n<p>Good news! The campaign <b>{name}</b> has been <b>activated</b>.</p>\r\n<p>Please open the <b>Social Gems</b> app to view the group details, join the campaign group, and start performing tasks.</p>\r\n', 'ALL', 'ANNOUNCEMENT', 'active'),
(33, 'PIN_RESET', 'Wallet Pin Reset', '<p>Hello {name},</p>\n<p>Your <b>SocialGems wallet PIN has been reset</b>.</p>\n<p>For your security, all <b>withdrawals have been suspended for 24 hours</b>.</p>\n<p>If this was <b>not</b> your action, please contact us immediately at <a href=\"mailto:info@{SITE_URL}\">info@{SITE_URL}</a>.</p>\n<p>Hello {name},</p> <p>Your <b>SocialGems wallet PIN has been reset</b>.</p> <p>For your security, all <b>withdrawals have been suspended for 24 hours</b>.</p> <p>If this was <b>not</b> your action, please contact us immediately at <a href=\"mailto:info@socialgems.me\">info@socialgems.me</a>.</p>', 'ALL', 'WALLET', 'active'),
(34, 'ADMIN_FORGOT_PASSWORD', 'Password Reset Request - Admin Panel', 'You have requested to reset your password for the Social Gems Admin Panel.<br><br>\r\n   <strong>Your OTP Code:</strong> {otp}<br><br>\r\n   This code will expire in 10 minutes.<br><br>\r\n   If you did not request this password reset, please ignore this email.<br><br>\r\n   <a href=\"{SITE_URL}reset-password?email={email}\" style=\"background-color: #ffcc66; color: #333333; padding: 10px 20px; text-decoration: none; border-radius: 5px; display: inline-block;\">Reset Password</a>', 'ALL', 'GENERAL', 'active'),
(35, 'ADMIN_PASSWORD_RESET_SUCCESS', 'Password Reset Successful - Admin Panel', 'Your password has been successfully reset for the Social Gems Admin Panel.<br><br>\n   If you did not make this change, please contact support immediately.<br><br>\n   <a href=\"{SITE_URL}login\" style=\"background-color: #ffcc66; color: #333333; padding: 10px 20px; text-decoration: none; border-radius: 5px; display: inline-block;\">Login to Admin Panel</a>', 'ALL', 'GENERAL', 'active'),
(36, 'DELETE_ACCOUNT', 'We’re sad to see you go – Account Deletion Confirmation', '<p>Hello {name},</p>\n\n<p>We’ve completed the deletion of your SocialGems account, as you requested.</p>\n\n<p>It’s always difficult to say goodbye, and we’re truly sad to see you leave our community. Your presence and contributions have meant a lot, and we hope SocialGems added value to your journey while you were here.</p>\n\n<p><b>What this means:</b></p>\n\n<p>Your account and profile have been permanently deleted.</p>\n\n<p>Any associated content has been removed from our platform.</p>\n\n<p>Minimal records may remain only where required for legal or security purposes.</p>\n\n<p>If you ever decide to return, please know that we’ll be here with open arms, ready to welcome you back and get you started again.</p>\n\n<p>Thank you for having been part of SocialGems. Wishing you the very best ahead.</p>\n\n<p>Best regards,<br>\nAngel</p>\n', 'APP', 'GENERAL', 'active'),
(37, 'ADD_AGENT', 'Social Gems Agent', '<p>Hello {name},</p>\n<p>You have been added to the Social Gems agent panel.</p>\n<p>Please use the following password to log in: <strong>{otp}</strong></p>\n<p>Visit the admin panel here: <a href=\"{AGENT_URL}\">{AGENT_URL}</a></p>\n', 'ALL', 'GENERAL', 'active'),
(38, 'RESET_AGENT_PASSWORD', 'Your Social Gems Agent Password Has Been Reset', 'Dear {name},<br><br>\r\n   Your Social Gems agent account password has been reset by an administrator.<br><br>\r\n   <strong>Your New Temporary Password:</strong> <strong>{otp}</strong><br><br>\r\n   Please log in to the agent portal using this temporary password and change it immediately for security purposes.<br><br>\r\n   <a href=\"{AGENT_URL}\" style=\"background-color: #ffcc66; color: #333333; padding: 10px 20px; text-decoration: none; border-radius: 5px; display: inline-block;\">Login to Agent Portal</a><br><br>\r\n   If you did not request this password reset, please contact our support team immediately.<br><br>\r\n   Best regards,<br>\r\n   The Social Gems Team', 'ALL', 'GENERAL', 'active'),
(39, 'SUBMISSION_REJECTED', 'Campaign Task Submission Rejected', 'Dear {name},<br><br>\r\n   Unfortunately, your task submission for a campaign has been rejected by the brand.<br><br>\r\n   <strong>Rejection Details:</strong><br>\r\n   Reason: {reason}<br><br>\r\n   Please review the campaign requirements and resubmit your work if applicable. If you have any questions about the rejection, please contact the campaign creator or our support team.<br><br>\r\n   <a href=\"https://app.socialgems.me/campaigns\" style=\"background-color: #ffcc66; color: #333333; padding: 10px 20px; text-decoration: none; border-radius: 5px; display: inline-block;\">View My Campaigns</a><br><br>\r\n   Best regards,<br>\r\n   The Social Gems Team', 'ALL', 'GENERAL', 'active'),
(40, 'CAMPAIGN_ACTIVATED_SENDER_EMAIL', 'Campaign Activated Successfully', 'Greetings,<br><br>\r\n   Great news! Your campaign <strong>{name}</strong> has been successfully activated and is now live.<br><br>\r\n   <strong>Campaign Details:</strong><br>\r\n   Campaign Name: {name}<br>\r\n   Status: <span style=\"color: #4CAF50; font-weight: bold;\">ACTIVE</span><br><br>\r\n   \r\n   <strong>What happens next?</strong><br>\r\n   ✓ Approved influencers can now start working on your campaign<br>\r\n   ✓ You can track progress in real-time from your dashboard<br>\r\n   ✓ You will receive notifications when influencers complete tasks<br>\r\n   ✓ You can review and approve submissions as they come in<br><br>\r\n   \r\n   \r\n   <strong>Need Help?</strong><br>\r\n   If you have any questions or need assistance managing your campaign, our support team is here to help.<br><br>\r\n   \r\n   Thank you for choosing Social Gems!<br><br>\r\n   Best regards,<br>', 'ALL', 'GENERAL', 'active');
